+
+const parseTrack = (value: string, min?: string): Track => {
+	if (value === 'auto') {
+		return {type: 'auto'};
+	}
+
+	if (value.endsWith('fr')) {
+		return {
+			type: 'fr',
+			value: Number.parseFloat(value),
